SELECT id, residence_history_id, operation_type, operated_by, operated_at,
       resident_name, dormitory_name, room_name
FROM residence_change_logs
WHERE 1 = 1

    AND operation_type = #{operationType}


    AND operated_at >= #{from}


    AND operated_at <= #{to}

ORDER BY operated_at DESC
LIMIT #{offset}, #{pageSize}

SELECT COUNT(1)
FROM residence_change_logs
WHERE 1 = 1

    AND operation_type = #{operationType}


    AND operated_at >= #{from}


    AND operated_at <= #{to}
